function getControlStatusSummary() {
    var totals = { total: exports.ADMIN_V4_CONTROLS_MAP.length, migrated: 0, missing: 0 };
    exports.ADMIN_V4_CONTROLS_MAP.forEach(function (item) {
        if (item.status === 'migrated')
            totals.migrated += 1;
        else
            totals.missing += 1;
    });
    return totals;
}
